import{_ as e,a as t,b as r,c as o}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as i,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Copia redundante y cambio de origen de lectura","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/redundant-backup-and-read-source.md","filePath":"es/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),c={name:"es/Other/redundant-backup-and-read-source.md"};function s(p,a,u,h,m,b){return i(),n("div",null,[...a[0]||(a[0]=[l('<h1 id="copia-redundante-y-cambio-de-origen-de-lectura" tabindex="-1">Copia redundante y cambio de origen de lectura <a class="header-anchor" href="#copia-redundante-y-cambio-de-origen-de-lectura" aria-label="Permalink to &quot;Copia redundante y cambio de origen de lectura&quot;">​</a></h1><p>La copia redundante guarda una copia adicional de archivos que ya fueron subidos.</p><p>Para los visitantes, el archivo principal y la copia se ven igual. La diferencia está en el canal de almacenamiento desde el que se lee realmente el archivo.</p><h2 id="que-permite-hacer" tabindex="-1">Qué permite hacer <a class="header-anchor" href="#que-permite-hacer" aria-label="Permalink to &quot;Qué permite hacer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>Descripción</th></tr></thead><tbody><tr><td>Guardar una copia extra</td><td>Copia el archivo a otro canal para reducir el riesgo de depender de un solo almacenamiento</td></tr><tr><td>Cambiar origen de lectura</td><td>Permite alternar entre el canal principal y el canal de copia</td></tr><tr><td>Copia de un archivo</td><td>Crear copia desde el detalle de un archivo concreto</td></tr><tr><td>Copia por lotes</td><td>Seleccionar varios archivos en el panel y copiarlos juntos</td></tr><tr><td>Copia global</td><td>Completar copias por carpeta desde Otros ajustes</td></tr></tbody></table><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; Copia redundante</span></span></code></pre></div><p><img src="'+e+'" alt="Copia redundante" loading="lazy"></p><p>Aquí puedes completar copias para una carpeta concreta o para todos los archivos. El canal de copia se puede elegir manualmente o dejar en modo automático para que ImgBed seleccione uno adecuado.</p><h2 id="copia-desde-el-detalle-del-archivo" tabindex="-1">Copia desde el detalle del archivo <a class="header-anchor" href="#copia-desde-el-detalle-del-archivo" aria-label="Permalink to &quot;Copia desde el detalle del archivo&quot;">​</a></h2><p>En el panel, abre el detalle de un archivo y usa la acción de copia.</p><p><img src="'+t+'" alt="Copia desde detalle" loading="lazy"></p><p>Este acceso es útil para proteger archivos importantes de forma puntual. Tras una copia correcta, el detalle mostrará los orígenes de lectura disponibles.</p><h2 id="copia-por-seleccion" tabindex="-1">Copia por selección <a class="header-anchor" href="#copia-por-seleccion" aria-label="Permalink to &quot;Copia por selección&quot;">​</a></h2><p>En el panel puedes seleccionar varios archivos y ejecutar una copia por lotes.</p><p><img src="'+r+'" alt="Copia por lotes" loading="lazy"></p><p>La copia desde detalle, la copia por selección y la copia redundante de Otros ajustes usan la misma lógica; solo cambia el punto de entrada.</p><h2 id="cambiar-el-origen-de-lectura" tabindex="-1">Cambiar el origen de lectura <a class="header-anchor" href="#cambiar-el-origen-de-lectura" aria-label="Permalink to &quot;Cambiar el origen de lectura&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Origen</th><th>Descripción</th></tr></thead><tbody><tr><td>Canal principal</td><td>Lee desde el canal donde se subió originalmente</td></tr><tr><td>Canal de copia</td><td>Lee desde el canal donde se guardó la copia redundante</td></tr></tbody></table><p><img src="'+o+'" alt="Cambiar origen" loading="lazy"></p><p>Después de cambiarlo, las imágenes, vídeos y enlaces de descarga seguirán funcionando con normalidad usando el origen elegido.</p><h2 id="casos-que-se-omiten" tabindex="-1">Casos que se omiten <a class="header-anchor" href="#casos-que-se-omiten" aria-label="Permalink to &quot;Casos que se omiten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caso</th><th>Motivo</th></tr></thead><tbody><tr><td>Ya tiene copia</td><td>Evita duplicar espacio innecesariamente</td></tr><tr><td>Canal principal y copia iguales</td><td>Copiar al mismo canal no aporta redundancia</td></tr><tr><td>No hay canal disponible</td><td>No se encontró otro canal adecuado</td></tr></tbody></table><h2 id="al-borrar-archivos" tabindex="-1">Al borrar archivos <a class="header-anchor" href="#al-borrar-archivos" aria-label="Permalink to &quot;Al borrar archivos&quot;">​</a></h2><p>Cuando borras un archivo, ImgBed elimina tanto el archivo principal como su copia.</p>',25)])])}const _=d(c,[["render",s]]);export{C as __pageData,_ as default};
